/**
 * Media Upload Component
 * Supports both images and videos with upload functionality
 * Author: generated by Amazon Q
 * Created: 2024-12-22
 */

'use client';

import React, { useState } from 'react';
import { Upload, X, Play } from 'lucide-react';

interface MediaUploadProps {
  src?: string;
  alt?: string;
  width?: number;
  height?: number;
  className?: string;
  onMediaChange?: (newSrc: string) => void;
  showUploadButton?: boolean;
  uploadButtonText?: string;
  acceptedTypes?: string;
}

export function MediaUpload({
  src = '',
  alt = '',
  width = 200,
  height = 120,
  className = '',
  onMediaChange,
  showUploadButton = true,
  uploadButtonText = 'Upload Media',
  acceptedTypes = 'image/*,video/*'
}: MediaUploadProps) {
  const [isUploading, setIsUploading] = useState(false);
  const [previewSrc, setPreviewSrc] = useState(src);

  // Update preview when src prop changes
  React.useEffect(() => {
    setPreviewSrc(src);
  }, [src]);

  // Detect if the source is a video
  const isVideo = (url: string) => {
    if (!url) return false;
    const videoExtensions = ['.mp4', '.webm', '.ogg', '.mov', '.avi'];
    return videoExtensions.some(ext => url.toLowerCase().includes(ext)) || 
           url.includes('video/') || 
           url.includes('mp4') || 
           url.includes('webm');
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsUploading(true);

    try {
      const formData = new FormData();
      formData.append('file', file);
      formData.append('type', 'media'); // Add required type parameter

      const response = await fetch('/api/admin/upload', {
        method: 'POST',
        body: formData,
      });

      if (response.ok) {
        const data = await response.json();
        const newSrc = data.url;
        setPreviewSrc(newSrc);
        onMediaChange?.(newSrc);
      } else {
        const errorData = await response.json();
        console.error('Upload failed:', errorData.error);
        alert(`Upload failed: ${errorData.error}`);
      }
    } catch (error) {
      console.error('Upload error:', error);
      alert('Upload failed. Please try again.');
    } finally {
      setIsUploading(false);
    }
  };

  const handleRemove = () => {
    setPreviewSrc('');
    onMediaChange?.('');
  };

  const renderMedia = () => {
    if (!previewSrc) {
      return (
        <div 
          className={`flex items-center justify-center bg-gray-100 dark:bg-gray-800 border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-md ${className}`}
          style={{ width, height }}
        >
          <div className="text-center">
            <Upload className="w-8 h-8 text-gray-400 mx-auto mb-2" />
            <p className="text-sm text-gray-500 dark:text-gray-400">No media</p>
          </div>
        </div>
      );
    }

    if (isVideo(previewSrc)) {
      return (
        <div className={`relative ${className}`} style={{ width, height }}>
          <video
            src={previewSrc}
            className="w-full h-full object-cover rounded-md"
            controls
            preload="metadata"
          />
          <div className="absolute top-2 right-2">
            <button
              onClick={handleRemove}
              className="p-1 bg-red-500 text-white rounded-full hover:bg-red-600 transition-colors"
              title="Remove video"
            >
              <X className="w-3 h-3" />
            </button>
          </div>
          <div className="absolute bottom-2 left-2 bg-black bg-opacity-50 text-white px-2 py-1 rounded text-xs">
            Video
          </div>
        </div>
      );
    }

    return (
      <div className={`relative ${className}`} style={{ width, height }}>
        <img
          src={previewSrc}
          alt={alt}
          className="w-full h-full object-cover rounded-md"
        />
        <div className="absolute top-2 right-2">
          <button
            onClick={handleRemove}
            className="p-1 bg-red-500 text-white rounded-full hover:bg-red-600 transition-colors"
            title="Remove image"
          >
            <X className="w-3 h-3" />
          </button>
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-2">
      {renderMedia()}
      
      {showUploadButton && (
        <div className="flex items-center gap-2">
          <label className="cursor-pointer">
            <input
              type="file"
              accept={acceptedTypes}
              onChange={handleFileUpload}
              className="hidden"
              disabled={isUploading}
            />
            <div className={`flex items-center gap-2 px-3 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 transition-colors text-sm ${
              isUploading ? 'opacity-50 cursor-not-allowed' : ''
            }`}>
              <Upload className="w-4 h-4" />
              {isUploading ? 'Uploading...' : uploadButtonText}
            </div>
          </label>
          
          {previewSrc && (
            <button
              onClick={handleRemove}
              className="px-3 py-2 bg-red-600 text-white rounded-md hover:bg-red-700 transition-colors text-sm"
            >
              Remove
            </button>
          )}
        </div>
      )}
    </div>
  );
}